import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   CONSTANTS & PRICING
   ============================================================================ */
const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1500, price: 40, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 4000, price: 90, label: 'Pro Reload', icon: Coins, bonus: '+200 Bonus', popular: true },
  { id: 'tu_4', amount: 10000, price: 150, label: 'Enterprise Reload', icon: ShieldCheck, bonus: '+1,000 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   PORTAL ADMIN (UI MOCK)
   ============================================================================ */
const AdminPortal = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full">
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0">
        <div className="h-20 flex items-center px-6 border-b border-slate-800 bg-slate-950">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white">
              <ShieldAlert size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg leading-tight tracking-tight">AR CONNECT</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">Admin Portal</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-600 mb-4 mt-4">Menu Utama</p>
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'users', icon: Users, label: 'User Management' },
            { id: 'settings', icon: Settings, label: 'System Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={18} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2 bg-slate-800 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">AD</div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold text-white truncate">{currentUser.nama_syarikat || 'Admin'}</p>
              <p className="text-[10px] text-slate-400 truncate">System Administrator</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-red-400 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 sticky top-0 z-10">
          <div><h2 className="text-xl font-black text-slate-800 capitalize">{activeTab}</h2></div>
        </header>
        <div className="flex-1 overflow-y-auto p-8 flex items-center justify-center text-slate-400 font-bold">
            Data pengguna sebenar akan disambungkan pada fasa pengurusan admin kelak.
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   PORTAL PENGGUNA (CLIENT) DENGAN INTEGRASI API SEBENAR
   ============================================================================ */
const UserPortal = ({ currentUser, token, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(currentUser.kredit || 0);

  // WhatsApp States
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle'); 
  const [qr, setQr] = useState(null);
  const isRequesting = useRef(false);

  // Blast States
  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [message, setMessage] = useState('');
  const [targetSource, setTargetSource] = useState('manual');
  const [manualNumbers, setManualNumbers] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('all');

  // Database Contacts States
  const [contacts, setContacts] = useState([]);
  const [newContact, setNewContact] = useState({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isUploadingCSV, setIsUploadingCSV] = useState(false); // State untuk fungsi CSV

  const uniqueGroups = useMemo(() => {
    const groups = new Set(contacts.map(c => c.kumpulan));
    return Array.from(groups);
  }, [contacts]);

  const fetchContacts = async () => {
    try {
      const res = await fetch(`${API_URL}/contacts/${currentUser.id}`);
      if (res.ok) {
        const data = await res.json();
        setContacts(data);
      }
    } catch (err) {
      console.error("Gagal load database", err);
    }
  };

  useEffect(() => {
    fetchContacts();
    // eslint-disable-next-line
  }, [activeTab]);

  const handleAddContact = async (e) => {
    e.preventDefault();
    if (!newContact.nombor_telefon) return;

    setIsAddingContact(true);
    try {
      const res = await fetch(`${API_URL}/contacts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id, ...newContact })
      });
      if (res.ok) {
        setNewContact({ nama: '', nombor_telefon: '', kumpulan: 'Umum' });
        fetchContacts();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsAddingContact(false);
    }
  };

  const handleDeleteContact = async (id) => {
    if (!window.confirm("Pasti mahu padam kenalan ini?")) return;
    try {
      const res = await fetch(`${API_URL}/contacts/${id}`, { method: 'DELETE' });
      if (res.ok) fetchContacts();
    } catch (err) {
      console.error(err);
    }
  };

  // --- FUNGSI BAHARU: Kendali Muat Naik CSV ---
  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsUploadingCSV(true);
    const reader = new FileReader();

    reader.onload = async (event) => {
      try {
        const csvText = event.target.result;
        // Sokong semua jenis line breaks (\n, \r\n, \r) dari pelbagai OS (Windows/Mac)
        const lines = csvText.split(/\r\n|\n|\r/); 
        const newContacts = [];

        for (let i = 0; i < lines.length; i++) {
          let line = lines[i].trim();
          if (!line) continue;

          // Pisahkan menggunakan koma (,) atau titik bertindih (;) atau tab (\t)
          const cols = line.split(/[,;\t]/);

          // Bersihkan 'quote' (") yang ditambah automatik oleh fail Excel
          let nama = cols[0] ? cols[0].replace(/"/g, '').trim() : '';
          let nombor = cols[1] ? cols[1].replace(/"/g, '').trim() : '';
          let kumpulan = cols[2] ? cols[2].replace(/"/g, '').trim() : '';

          // Jika nombor tiada di column 2, cuba semak jika Excel longgok semua di column 1
          if (!nombor && nama) {
              const possibleNumber = nama.replace(/[^0-9]/g, '');
              if (possibleNumber.length > 8) {
                  nombor = possibleNumber;
                  nama = 'Pelanggan';
              }
          }

          // Langkau baris pertama jika ia adalah 'Header'
          if (i === 0 && (nama.toLowerCase().includes('nama') || (nombor && nombor.toLowerCase().includes('nombor')))) continue;

          const cleanPhone = nombor ? nombor.replace(/[^0-9]/g, '') : '';

          // Wajibkan nombor wujud dan panjang rasional (>8 digit)
          if (!cleanPhone || cleanPhone.length < 8) continue; 

          newContacts.push({
            nama: nama || 'Pelanggan',
            nombor_telefon: cleanPhone,
            kumpulan: kumpulan || 'CSV Import'
          });
        }

        if (newContacts.length === 0) {
          alert("Tiada data yang sah dijumpai. Pastikan fail mengandungi nombor telefon.");
          setIsUploadingCSV(false);
          return;
        }

        // Hantar array ke server backend untuk bulk insert
        const res = await fetch(`${API_URL}/contacts/bulk`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ user_id: currentUser.id, contacts: newContacts })
        });

        if (res.ok) {
          alert(`${newContacts.length} kenalan dari CSV berjaya diimport!`);
          fetchContacts(); // Segar semula senarai
        } else {
          const data = await res.json();
          alert(`Ralat Server: ${data.message || 'Gagal memproses fail'}`);
        }
      } catch (err) {
        console.error("Ralat membaca fail CSV", err);
        alert("Gagal membaca struktur fail CSV.");
      } finally {
        setIsUploadingCSV(false);
        if (e.target) e.target.value = null; // Reset nilai input fail supaya boleh upload fail sama berkali-kali
      }
    };

    reader.readAsText(file);
  };

  const connectWA = async () => {
    setQrStatus('loading');
    setQr(null);
    try {
      const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
      if (!res.ok) throw new Error("Gagal hubungi server");
    } catch (err) {
      console.error(err);
      setQrStatus('error');
    }
  };

  const logoutWA = async () => {
    setQrStatus('disconnecting');
    try {
      await fetch(`${API_URL}/whatsapp/logout`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ userId: currentUser.id })
      });
    } catch (err) {
      console.error("Gagal putuskan sambungan dari server:", err);
    }
    setQrStatus('idle');
    setIsDeviceLinked(false);
    setQr(null);
  };

  useEffect(() => {
    let interval;
    let isMounted = true;

    const checkServerStatus = async () => {
      if (isRequesting.current) return; 
      isRequesting.current = true;

      try {
        const res = await fetch(`${API_URL}/whatsapp/connect/${currentUser.id}`);
        const data = await res.json();
        if (!isMounted) return;

        if (data.status === 'connected' || data.connected) {
          setQrStatus('connected');
          setIsDeviceLinked(true);
          setQr(null);
        } else if (data.status === 'disconnected') { 
          setQrStatus('idle');
          setIsDeviceLinked(false);
          setQr(null);
        } else if (data.qr && qrStatus !== 'connected') {
          setQr(prevQr => prevQr !== data.qr ? data.qr : prevQr);
          setQrStatus('qr_ready');
        }
      } catch (err) {
      } finally {
        isRequesting.current = false;
      }
    };

    if (qrStatus === 'loading' || qrStatus === 'qr_ready') {
      interval = setInterval(checkServerStatus, 1500);
    } else if (qrStatus === 'connected') {
      interval = setInterval(checkServerStatus, 5000);
    }

    return () => {
      isMounted = false;
      if (interval) clearInterval(interval);
    };
  }, [qrStatus, currentUser.id]);

  const startBlast = async () => {
    if (!isDeviceLinked) { 
      alert("Sila hubungkan WhatsApp anda terlebih dahulu!");
      setActiveTab('dashboard'); 
      return; 
    }

    let numbers = [];

    if (targetSource === 'manual') {
      numbers = manualNumbers.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 5);
    } else if (targetSource === 'database') {
      const filteredContacts = selectedGroup === 'all' 
        ? contacts 
        : contacts.filter(c => c.kumpulan === selectedGroup);
      numbers = filteredContacts.map(c => c.nombor_telefon);
