                    )}

                    {targetSource === 'database' && (
                      <div className="space-y-3 animate-in fade-in zoom-in-95 p-5 bg-green-50 border-2 border-green-100 rounded-2xl">
                        <label className="text-[10px] font-black text-green-600 uppercase tracking-widest flex items-center gap-2"><Database size={14}/> Kumpulan Sasaran</label>
                        <select value={selectedGroup} onChange={(e) => setSelectedGroup(e.target.value)} className="w-full p-4 bg-white rounded-xl font-bold text-slate-700 outline-none border border-slate-200 focus:border-green-500">
                          <option value="all">🚀 Semua Kenalan ({contacts.length} nombor)</option>
                          {uniqueGroups.map((group, idx) => (
                            <option key={idx} value={group}>📁 Kumpulan: {group} ({contacts.filter(c => c.kumpulan === group).length} nombor)</option>
                          ))}
                        </select>
                      </div>
                    )}

                    <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Kandungan Mesej</label>
                      <textarea value={message} onChange={(e) => setMessage(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none h-40 font-medium text-slate-700 focus:border-green-500 transition-all resize-none" placeholder="Taipkan mesej WhatsApp anda di sini..." />
                    </div>
                  </div>

                  {isBlasting ? (
                    <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                      <div className="flex justify-between items-center mb-4">
                        <span className="font-black text-green-500">Menghantar Melalui Server...</span>
                        <span className="font-bold text-slate-400">{messagesSent} Hantar</span>
                      </div>
                      <div className="w-full h-4 bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full bg-green-500 transition-all duration-200" style={{ width: `${blastProgress}%` }}></div>
                      </div>
                    </div>
                  ) : (
                    <button onClick={startBlast} className="w-full py-6 bg-green-500 text-white rounded-[2.5rem] font-black text-xl hover:bg-green-600 shadow-xl shadow-green-200 transition-all flex items-center justify-center gap-3">
                      <Send size={24} /> MULA KEMPEN BLAST
                    </button>
                  )}
                </div>

                <div className="lg:col-span-5">
                  <div className="bg-[#e5ddd5] rounded-[3rem] p-4 shadow-2xl border-[12px] border-slate-900 h-[650px] relative flex flex-col overflow-hidden">
                    <div className="bg-[#075e54] text-white p-4 rounded-t-[2rem] -mx-4 -mt-4 flex items-center gap-3 z-10 shadow-md">
                      <div className="w-9 h-9 rounded-full bg-slate-200 flex items-center justify-center overflow-hidden">
                        <User size={20} className="text-slate-400 mt-2" />
                      </div>
                      <div>
                        <p className="text-xs font-bold">Customer Preview</p>
                        <p className="text-[9px] opacity-70">online</p>
                      </div>
                    </div>
                    <div className="flex-1 overflow-y-auto p-4 space-y-4 pt-6">
                      <div className="bg-white p-3 rounded-2xl rounded-tl-none shadow-sm max-w-[85%] relative">
                        <p className="text-sm text-slate-800 whitespace-pre-wrap">{message || "Mesej anda akan dipaparkan di sini..."}</p>
                        <p className="text-[9px] text-slate-400 text-right mt-1">12:00 PM</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   KOMPONEN UTAMA APP (PENGURUSAN LOGIN & REGISTER SEBENAR)
   ============================================================================ */
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState('');
  const [viewMode, setViewMode] = useState('login'); 

  const [formData, setFormData] = useState({ email: '', password: '', nama_syarikat: '' });
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    const savedUser = localStorage.getItem('user');
    const savedToken = localStorage.getItem('token');
    if (savedUser && savedToken) {
      setCurrentUser(JSON.parse(savedUser));
      setToken(savedToken);
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');
    setSuccessMsg('');

    const endpoint = viewMode === 'login' ? '/auth/login' : '/auth/register';
    const payload = viewMode === 'login' 
      ? { email: formData.email, kata_laluan: formData.password }
      : { email: formData.email, kata_laluan: formData.password, nama_syarikat: formData.nama_syarikat };

    try {
      const res = await fetch(`${API_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();

      if (!res.ok) throw new Error(data.message || 'Sesuatu tidak kena, sila cuba lagi.');

      if (viewMode === 'login') {
        localStorage.setItem('token', data.token);
        const userData = { ...data.user, id: data.user.id }; 
        localStorage.setItem('user', JSON.stringify(userData));
        setToken(data.token);
        setCurrentUser(userData);
      } else {
        setSuccessMsg('Pendaftaran berjaya! Sila log masuk.');
        setViewMode('login');
      }
    } catch (err) {
      setErrorMsg(err.message);
    } finally {
      setLoading(false);
    }
  };

  const onLogout = () => {
    localStorage.clear();
    setCurrentUser(null);
    setToken('');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl shadow-slate-200 border border-white p-10">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-green-500 rounded-2xl flex items-center justify-center mx-auto mb-4 rotate-3 shadow-lg shadow-green-200">
              <Zap size={32} className="text-white fill-current" />
            </div>
            <h1 className="text-3xl font-black tracking-tighter text-slate-900">AR CONNECT</h1>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Sistem Terhubung Penuh</p>
          </div>

          {errorMsg && (
            <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-red-50 text-red-500">
              <AlertCircle size={16} /> {errorMsg}
            </div>
          )}
          {successMsg && (
            <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-green-50 text-green-500">
              <CheckCircle2 size={16} /> {successMsg}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-4">
            {viewMode === 'register' && (
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Syarikat</label>
                 <input 
                   type="text" 
                   onChange={(e) => setFormData({...formData, nama_syarikat: e.target.value})} 
                   placeholder="cth: AR Global" 
                   required 
                   className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" 
                 />
               </div>
            )}
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
              <input 
                type="email" 
                onChange={(e) => setFormData({...formData, email: e.target.value})} 
                placeholder="cth: admin@arconnect.my" 
                required 
                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Kata Laluan</label>
              <input 
                type="password" 
                placeholder="••••••••" 
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                required 
                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all" 
              />
            </div>
            <button disabled={loading} type="submit" className="w-full py-5 bg-green-500 text-white rounded-2xl font-black hover:bg-green-600 transition shadow-xl shadow-green-100 mt-4 uppercase tracking-widest flex justify-center items-center gap-2">
              {loading ? <Loader2 className="animate-spin" /> : (viewMode === 'login' ? <LogIn size={20} /> : <PlusCircle size={20} />)} 
              {viewMode === 'login' ? 'Log Masuk' : 'Daftar Akaun'}
            </button>
          </form>

          <div className="mt-8 text-center">
            <button 
              onClick={() => {
                setErrorMsg('');
                setSuccessMsg('');
                setViewMode(viewMode === 'login' ? 'register' : 'login');
              }}
              className="text-sm font-black text-slate-400 hover:text-green-600 transition"
            >
              {viewMode === 'login' ? "Tiada akaun? Daftar sekarang" : "Sudah ada akaun? Log Masuk"}
            </button>
          </div>
          <p className="text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-10">
            &copy; 2024 AR CONNECT TECHNOLOGY
          </p>
        </div>
      </div>
    );
  }

  if (currentUser.email === 'admin@arconnect.my') {
    return <AdminPortal currentUser={currentUser} onLogout={onLogout} />;
  }

  return <UserPortal currentUser={currentUser} token={token} onLogout={onLogout} />;
}
